SELECT SUM(trading_volume) AS total_trading_volume
FROM trading_days
WHERE trading_day = '2007-05-25';

SELECT close_price
FROM stocks
WHERE symbol = '1' AND timestamp = '1';

SELECT company_name
FROM stock_symbols
WHERE symbol = '1';

SELECT trading_volume
FROM trading_days
WHERE trading_day = '0';

SELECT symbol, MAX(close_price) AS highest_close_price
FROM stocks
WHERE symbol = '1';

SELECT high_price AS peak_trading_value
FROM stocks
WHERE symbol = '1' AND timestamp = '1';
